const raw = $json;
const stopReason = raw.stop_reason;
const text = (raw.content?.[0]?.text || '').trim();

if (!text) throw new Error('Empty response from Claude');

if (stopReason === 'max_tokens') {
  throw new Error('Claude hit the token limit — response was truncated. Increase maxTokensToSample. Response ends with: ...' + text.slice(-120));
}

const fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
const clean = fenceMatch ? fenceMatch[1].trim() : text;
const start = clean.indexOf('{');
const end = clean.lastIndexOf('}');

if (start === -1 || end <= start) {
  const truncated = !clean.trimEnd().endsWith('}');
  if (truncated) throw new Error('Response appears truncated (no closing brace). Last 120 chars: ...' + clean.slice(-120));
  throw new Error('No JSON object found. Preview: ' + text.substring(0, 300));
}

const jsonStr = clean.slice(start, end + 1);

// Attempt 1: raw parse
try {
  return { json: JSON.parse(jsonStr) };
} catch (_) {}

// Attempt 2: strip // comment lines and trailing commas, then re-parse
try {
  const fixed = jsonStr
    .replace(/^\s*\/\/.*$/gm, '')
    .replace(/,(\s*[}\]])/g, '$1');
  return { json: JSON.parse(fixed) };
} catch (e2) {
  throw new Error('Parse failed after cleanup: ' + e2.message + '. Last 300 chars: ...' + jsonStr.slice(-300));
}
